// Pull both runs' ensures-conjuncts into the proof context so the
// shared spec terms `pre_self_@.index(i as int)` and
// `pre_self_@.remove(i as int)` appear with identical trigger shapes
// for r1 and r2. The original file-level `unknown` is the classic
// "two foralls with disjoint triggers" gap; restating each conjunct
// forces z3 to see the shared pre-state expressions.
assert(r1 == pre_self_@.index(i as int));
assert(r2 == pre_self_@.index(i as int));
assert(post1_self_@ == pre_self_@.remove(i as int));
assert(post2_self_@ == pre_self_@.remove(i as int));
assert(post1_self_@.to_set() == pre_self_@.to_set().remove(r1));
assert(post2_self_@.to_set() == pre_self_@.to_set().remove(r2));
assert(post1_self_.valid());
assert(post2_self_.valid());

// Transitive collapse: r1 and r2 are both the same indexed element,
// and post1_self_@, post2_self_@ are both the same removed sequence.
assert(r1 == r2);
assert(post1_self_@ =~= post2_self_@);
assert(post1_self_@ == post2_self_@);
assert(post1_self_@.to_set() == post2_self_@.to_set());
